#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
LL a,b,p;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
LL GCD(LL x,LL y){
    if(x<y)swap(x,y);
    return (y?GCD(y,x%y):x);
}
LL QP(LL x,LL y,LL mod){
    LL as=1;
    while(y){
        if(y&1)as=as*x%mod;
        x=x*x%mod,y>>=1;
    }return as;
}
LL BSGS(LL x,LL y,LL mod){
    unordered_map<LL,LL> mp;
    mp.clear();
    x%=mod,y%=mod;
    LL m=sqrt(mod)+2,tmp=y;
    for(int i=1;i<=m;i++)
        tmp=((_i128)(tmp)*x)%mod,mp[tmp]=i;
    LL fan=QP(x,m,mod);tmp=1;
    for(int i=1;i<=m;i++){
        tmp=((_i128)(tmp)*fan)%mod;
        if(mp[tmp]>0)return i*m-mp[tmp];
    }return -1;
}
LL exGCD(LL a,LL b,LL &x,LL &y){
    if(!b){x=1,y=0;return a;}
    LL yu=exGCD(b,a%b,x,y);
    LL tmp=x;x=y,y=tmp-a/b*y;
    return yu;
}
LL calc_inv(LL a,LL mod){
    LL x=0,y=0;
    exGCD(a,mod,x,y);
    return (x%mod+mod)%mod;
}
LL exBSGS(LL x,LL y,LL mod){
    LL A=1,k=0,p=mod;
    x%=mod,y%=mod;
    if(y==1||mod==1)return 0;
    while(1){
        LL g=GCD(x,p);
        if(g==1)break;
        if(y%g!=0)return -1;
        k++,y/=g,p/=g;
        A=((_i128)(A)*x/g)%p;
        if(A==y)return k;
    }
    LL inv_A=calc_inv(A,p);
    LL new_y=(_i128)(y)*inv_A%p;
    LL res=BSGS(x,new_y,p);
    if(res==-1)return -1;
    else return res+k;
}
int main(){
    while(1){
        a=read(),p=read(),b=read();
        if(!a&&!b&&!p)break;
        LL Ans=exBSGS(a,b,p);
        if(Ans==-1)cout<<"No Solution\n";
        else cout<<Ans<<"\n";
    }
    return 0;
}
